"""
文件操作与删除工具模块（沙箱安全测试版）
"""
import os
import json
from pathlib import Path
from typing import Dict, Any, Optional

# 配置
config = {
    "base_path": "./",
    "allow_delete": False
}

def _get_safe_path(file_path: str) -> Path:
    """获取安全的文件路径，确保在基础路径内"""
    base = Path(config.get("base_path", "./")).resolve()
    target = (base / file_path).resolve()

    # 确保目标路径在基础路径内
    if not str(target).startswith(str(base)):
        raise ValueError(f"路径 {file_path} 超出允许范围")

    return target

def read_file(file_path: str, encoding: str = "utf-8") -> Dict[str, Any]:
    """
    读取文件内容（沙箱安全版）

    参数:
        file_path: 文件路径
        encoding: 文件编码，默认为utf-8

    返回:
        文件内容和元信息
    """
    try:
        safe_path = _get_safe_path(file_path)

        if not safe_path.exists():
            return {"error": f"文件 {file_path} 不存在"}

        if not safe_path.is_file():
            return {"error": f"{file_path} 不是文件"}

        with open(safe_path, 'r', encoding=encoding) as f:
            content = f.read()

        return {
            "path": file_path,
            "content": content,
            "size": safe_path.stat().st_size,
            "encoding": encoding,
            "lines": len(content.splitlines()),
            "success": True
        }

    except Exception as e:
        return {"error": str(e), "success": False}

def write_file(file_path: str, content: str, encoding: str = "utf-8") -> Dict[str, Any]:
    """
    写入文件内容（沙箱安全版）

    参数:
        file_path: 文件路径
        content: 文件内容
        encoding: 文件编码，默认为utf-8

    返回:
        操作结果
    """
    try:
        safe_path = _get_safe_path(file_path)

        # 确保父目录存在
        safe_path.parent.mkdir(parents=True, exist_ok=True)

        with open(safe_path, 'w', encoding=encoding) as f:
            f.write(content)

        return {
            "path": file_path,
            "size": len(content.encode(encoding)),
            "encoding": encoding,
            "success": True
        }

    except Exception as e:
        return {"error": str(e), "success": False}

def create_directory(directory_path: str) -> Dict[str, Any]:
    """
    创建目录（沙箱安全版）

    参数:
        directory_path: 目录路径

    返回:
        操作结果
    """
    try:
        safe_path = _get_safe_path(directory_path)

        if safe_path.exists():
            return {"error": f"路径 {directory_path} 已存在"}

        safe_path.mkdir(parents=True, exist_ok=True)

        return {
            "path": directory_path,
            "success": True
        }

    except Exception as e:
        return {"error": str(e), "success": False}

def delete_file(file_path: str) -> Dict[str, Any]:
    """
    删除文件（沙箱安全版）

    参数:
        file_path: 文件路径

    返回:
        操作结果
    """
    try:
        if not config.get("allow_delete", False):
            return {"error": "删除操作被禁用", "success": False}

        safe_path = _get_safe_path(file_path)

        if not safe_path.exists():
            return {"error": f"文件 {file_path} 不存在", "success": False}

        if not safe_path.is_file():
            return {"error": f"{file_path} 不是文件", "success": False}

        safe_path.unlink()

        return {
            "path": file_path,
            "type": "file",
            "success": True
        }

    except Exception as e:
        return {"error": str(e), "success": False}

def delete_directory(directory_path: str) -> Dict[str, Any]:
    """
    删除目录（沙箱安全版）

    参数:
        directory_path: 目录路径

    返回:
        操作结果
    """
    try:
        if not config.get("allow_delete", False):
            return {"error": "删除操作被禁用", "success": False}

        safe_path = _get_safe_path(directory_path)

        if not safe_path.exists():
            return {"error": f"目录 {directory_path} 不存在", "success": False}

        if not safe_path.is_dir():
            return {"error": f"{directory_path} 不是目录", "success": False}

        # 检查目录是否为空
        if any(safe_path.iterdir()):
            return {"error": f"目录 {directory_path} 不为空", "success": False}

        safe_path.rmdir()

        return {
            "path": directory_path,
            "type": "directory",
            "success": True
        }

    except Exception as e:
        return {"error": str(e), "success": False}
